import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"阶段三：多模态 / 向量检索 / 知识图谱规划【进阶可选】","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/ai/phase3-multimodal-kg.md","filePath":"tech-system/ai/phase3-multimodal-kg.md"}'),t={name:"tech-system/ai/phase3-multimodal-kg.md"};function o(h,l,n,s,d,u){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="阶段三-多模态-向量检索-知识图谱规划【进阶可选】" tabindex="-1">阶段三：多模态 / 向量检索 / 知识图谱规划【进阶可选】 <a class="header-anchor" href="#阶段三-多模态-向量检索-知识图谱规划【进阶可选】" aria-label="Permalink to “阶段三：多模态 / 向量检索 / 知识图谱规划【进阶可选】”">​</a></h1><blockquote><p>这一篇属于<strong>进阶选修</strong>，适合在你已经有了 LLM + MVP Server 雏形以后，想做更聪明一点的“知识库问答 / 投资分析助手”等应用时再看。</p></blockquote><hr><h2 id="_1-这一阶段的定位" tabindex="-1">1. 这一阶段的定位 <a class="header-anchor" href="#_1-这一阶段的定位" aria-label="Permalink to “1. 这一阶段的定位”">​</a></h2><ul><li>不再满足于“关键字搜索 + 模型总结”，<br> 而是希望模型能： <ul><li>根据语义相似度<strong>找到最相关的内容</strong>（RAG / 向量检索）。</li><li>处理“图结构”的关系数据（例如公司—高管—事件—行业）。</li><li>结合文本 + 图片 或其他模态做更复杂的分析。</li></ul></li></ul><hr><h2 id="_2-学习目标拆解" tabindex="-1">2. 学习目标拆解 <a class="header-anchor" href="#_2-学习目标拆解" aria-label="Permalink to “2. 学习目标拆解”">​</a></h2><ol><li><strong>理解并能实践 RAG（检索增强生成）</strong> 的基本流程。</li><li>会使用一个向量数据库（例如 Milvus / Weaviate / 本地向量库）。</li><li>对图数据库（Neo4j 等）有基础认识，知道什么时候用“图结构”比表更合适。</li><li>如果你有投资 / 行业分析兴趣，可以做一个<strong>结合新闻 + 关系图的小知识库项目</strong>。</li></ol><hr><h2 id="_3-时间规划建议-2-4-周-可拉长分散进行" tabindex="-1">3. 时间规划建议（2～4 周，可拉长分散进行） <a class="header-anchor" href="#_3-时间规划建议-2-4-周-可拉长分散进行" aria-label="Permalink to “3. 时间规划建议（2～4 周，可拉长分散进行）”">​</a></h2><h3 id="第-1-周-rag-向量检索基础" tabindex="-1">第 1 周：RAG &amp; 向量检索基础 <a class="header-anchor" href="#第-1-周-rag-向量检索基础" aria-label="Permalink to “第 1 周：RAG &amp; 向量检索基础”">​</a></h3><ul><li>理解核心概念： <ul><li>Embedding：把文本转换成向量表示。</li><li>向量相似度：余弦相似度 / 内积等。</li><li>RAG 流程： <ol><li>用户提问。</li><li>用 Embedding 把问题向量化。</li><li>在向量库里检索最相似的 N 段文本。</li><li>把这些文本作为 context 一起发送给 LLM 生成回答。</li></ol></li></ul></li><li>实战任务： <ul><li>选你某一个模块的笔记（如数据库 / Java 并发），</li><li>做一个极简 RAG Demo： <ul><li>预先把若干段笔记向量化存入向量库。</li><li>提问时检索最相近的 3～5 段，再交给 LLM 回答。</li></ul></li></ul></li></ul><h3 id="第-2-周-接入真实知识库-结合你现有笔记" tabindex="-1">第 2 周：接入真实知识库（结合你现有笔记） <a class="header-anchor" href="#第-2-周-接入真实知识库-结合你现有笔记" aria-label="Permalink to “第 2 周：接入真实知识库（结合你现有笔记）”">​</a></h3><ul><li>选一个你最常用的内容源： <ul><li>你的 VitePress 文档（面试笔记库）。</li><li>或者公开的技术文档/教程。</li></ul></li><li>实战任务： <ul><li>写一个“离线构建向量库”的脚本： <ol><li>扫描 Markdown 文档。</li><li>按小段落切分（如每 200～500 字一块）。</li><li>为每块生成 Embedding，存入向量数据库。</li></ol></li><li>写一个“在线问答接口”： <ul><li>输入：问题 + 可选模块过滤（如只查数据库）。</li><li>输出：LLM 基于检索结果的回答 + 引用来源。</li></ul></li></ul></li></ul><h3 id="第-3-4-周-知识图谱与图数据库-兴趣向" tabindex="-1">第 3～4 周：知识图谱与图数据库（兴趣向） <a class="header-anchor" href="#第-3-4-周-知识图谱与图数据库-兴趣向" aria-label="Permalink to “第 3～4 周：知识图谱与图数据库（兴趣向）”">​</a></h3><ul><li>理解图数据库适用的场景： <ul><li>实体多、关系复杂、需要做路径查询或关联分析时更适用。</li><li>例如：公司—高管—供应链—事件—行业。</li></ul></li><li>实战任务（可简化）： <ul><li>用 Neo4j 或其他图数据库建一个小图： <ul><li>节点：公司、技术栈、项目。</li><li>关系：<code>公司-使用-&gt;技术栈</code>、<code>公司-包含-&gt;项目</code> 等。</li></ul></li><li>练习几条基本查询： <ul><li>“使用 Java 的公司有哪些？”</li><li>“和某技术栈最相关的其它技术有哪些？”</li></ul></li></ul></li></ul><blockquote><p>如果你觉得图数据库上手成本太高，可以先只当作了解概念，RAG 这块打牢就已经很有价值。</p></blockquote><hr><h2 id="_4-针对不同学习目的的取舍" tabindex="-1">4. 针对不同学习目的的取舍 <a class="header-anchor" href="#_4-针对不同学习目的的取舍" aria-label="Permalink to “4. 针对不同学习目的的取舍”">​</a></h2><h3 id="目的-a-只想做一个-更好用的学习-面试助手" tabindex="-1">目的 A：只想做一个“更好用的学习/面试助手” <a class="header-anchor" href="#目的-a-只想做一个-更好用的学习-面试助手" aria-label="Permalink to “目的 A：只想做一个“更好用的学习/面试助手””">​</a></h3><ul><li>重点完成： <ul><li>基于你 VitePress 文档的 RAG 问答系统。</li><li>即：输入问题 → 检索相关笔记段落 → LLM 输出答案 + 参考来源。</li></ul></li><li>图数据库可以暂时不做，留在以后有时间/有具体需求再看。</li></ul><h3 id="目的-b-对数据分析-投资类应用感兴趣" tabindex="-1">目的 B：对数据分析 / 投资类应用感兴趣 <a class="header-anchor" href="#目的-b-对数据分析-投资类应用感兴趣" aria-label="Permalink to “目的 B：对数据分析 / 投资类应用感兴趣”">​</a></h3><ul><li>可以在 RAG 之上多做一步： <ul><li>把“公司—新闻—指标”抽象成简单的图结构，</li><li>用图数据库来做： <ul><li>间接关联查询（一个公司关联到哪些事件 / 行业风险）。</li><li>上下游链路分析。</li></ul></li></ul></li></ul><h3 id="目的-c-长期考虑向-ai-平台-数据平台方向发展" tabindex="-1">目的 C：长期考虑向 AI 平台 / 数据平台方向发展 <a class="header-anchor" href="#目的-c-长期考虑向-ai-平台-数据平台方向发展" aria-label="Permalink to “目的 C：长期考虑向 AI 平台 / 数据平台方向发展”">​</a></h3><ul><li>建议： <ul><li>把这一阶段当作“工具箱”，不用急着一次性学完。</li><li>每当实际项目遇到“搜索 / 关联分析”问题，就回来翻这一篇，按需学习。</li></ul></li></ul><hr><h2 id="_5-如何与前两阶段衔接" tabindex="-1">5. 如何与前两阶段衔接 <a class="header-anchor" href="#_5-如何与前两阶段衔接" aria-label="Permalink to “5. 如何与前两阶段衔接”">​</a></h2><ul><li>在阶段一，你已经会用 LLM + Agent 做问答和小工具。</li><li>在阶段二，你把你的学习资料/业务数据整理成统一接口（MVP Server）。</li><li>到了阶段三，只是在此基础上再加一层： <ul><li><strong>“检索更准”（RAG / 向量库）</strong></li><li><strong>“关系更清晰”（图结构）</strong></li></ul></li></ul><p>最终，你可以得到一个：<br><strong>“我的专属技术/投资知识库机器人”</strong>——<br> 既能查你自己整理的笔记，又能看懂更复杂的数据关系，而不仅仅是“小聊天机器人”。</p>',29)])])}const b=i(t,[["render",o]]);export{m as __pageData,b as default};
